PlantUML:
@startuml
title ATM Extended State Machine - Adding Transitions

state "ReadAmount <<extended>>" as ReadAmount {
  state "SelectAmount <<extended>>" as SelectAmount
  state "EnterAmount <<extended>>" as EnterAmount
}

state "ReleaseCard <<extended>>" as ReleaseCard

SelectAmount --> ReleaseCard : abort
EnterAmount --> ReleaseCard : abort

@enduml

@startuml
title ATM State Machine (Extended)

state "ReadAmount <<extended>>" as ReadAmount {

  state "SelectAmount <<extended>>" as SelectAmount
  state EnterAmount
  state E <<choice>>

  SelectAmount --> EnterAmount : otherAmount
  EnterAmount --> E : ok
}

state "VerifyTransaction <<extended>>" as VerifyTransaction

VerifyTransaction --> EnterAmount : rejectTransaction

@enduml

@startuml
title Initial state machine for StaffMember

[*] --> Employed : /assignNewStaffGrade()

state Employed {

  state "Staff Contact" as StaffContact {
    [*] --> NotAssigned

    state NotAssigned
    state AssignedCampaign

    NotAssigned --> AssignedCampaign : assignStaffContact() / client.assignStaffContact()
    AssignedCampaign --> NotAssigned : removeStaffContact() / client.assignStaffContact()

    AssignedCampaign : exit / removeStaffcontact;
  }

  --

  state "Campaign Staff" as CampaignStaffRegion {
    [*] --> NotCampaignStaff

    state NotCampaignStaff
    state CampaignStaff

    NotCampaignStaff --> CampaignStaff : assignStaff() / campaign.assignStaff()
    CampaignStaff --> NotCampaignStaff : removeStaff() / campaign.removeStaff()

    CampaignStaff : exit / removeStaff();
  }
}

state "Ex-employee" as ExEmployee

Employed --> ExEmployee : leaveEmployment
ExEmployee --> [*] : after (1 year) / archive()

@enduml
